// ================================================================
// FP Romania - Shared logo assets (base64 PNG)
// ================================================================
// Extract des logos embedded dans la page de login pour reutilisation
// (onboarding tour, etc.) sans duplication de ~47KB de base64.
// Loaded before mobile.js / onboarding-tour.js.
// ================================================================
(function() {
  window.FP_LOGO_PNG = 'data:image/png;base64,';
  window.ISSEO_LOGO_PNG = 'data:image/png;base64,';
})();

// v6.51 — Pin FITNESS PARK fidèle à l'image de référence (cercle gris clair
// + texte FITNESS PARK complet + swoosh jaune), animations apple-like
// (spring appear, hover lift, active pulse, swoosh trace-in).
(function () {
  let _styleInjected = false;
  function injectStyle() {
    if (_styleInjected || typeof document === 'undefined') return;
    _styleInjected = true;
    const style = document.createElement('style');
    style.textContent = `
      .fp-logo-pin {
        transform-origin: center;
        transition: transform .35s cubic-bezier(.34,1.56,.64,1), box-shadow .28s cubic-bezier(.2,.8,.2,1), filter .2s ease-out;
        animation: fpPinDrop .65s cubic-bezier(.34,1.56,.64,1) both;
        will-change: transform;
      }
      .fp-logo-pin:hover {
        transform: scale(1.1);
        z-index: 1000;
        filter: brightness(1.06);
      }
      .fp-logo-pin:active {
        transform: scale(0.94);
        transition: transform .08s cubic-bezier(.3,0,.7,1);
      }
      .fp-logo-pin.fp-pin-active {
        animation: fpPinPulseSoft 2.4s cubic-bezier(.4,0,.6,1) infinite;
      }
      .fp-logo-pin__swoosh {
        stroke-dasharray: 200;
        stroke-dashoffset: 200;
        animation: fpSwooshDraw 0.9s cubic-bezier(.22,1,.36,1) .25s forwards;
      }
      @keyframes fpPinDrop {
        0%   { transform: scale(0.3) translateY(-18px); opacity: 0; }
        55%  { transform: scale(1.12) translateY(0); opacity: 1; }
        78%  { transform: scale(0.96) translateY(0); }
        100% { transform: scale(1) translateY(0); opacity: 1; }
      }
      @keyframes fpPinPulseSoft {
        0%, 100% { transform: scale(1.06); }
        50%      { transform: scale(1.14); }
      }
      @keyframes fpSwooshDraw {
        to { stroke-dashoffset: 0; }
      }
      @media (prefers-reduced-motion: reduce) {
        .fp-logo-pin,
        .fp-logo-pin.fp-pin-active,
        .fp-logo-pin__swoosh { animation: none !important; }
        .fp-logo-pin__swoosh { stroke-dashoffset: 0 !important; }
      }
    `;
    document.head.appendChild(style);
  }

  /**
   * Pin FP stylé (cercle blanc cassé, texte "FITNESS PARK", swoosh jaune).
   * Opts: { size = 48, active = false, num = null }
   * Taille 48px par défaut → "FITNESS PARK" lisible sur carte.
   */
  window.fpLogoPinHTML = function fpLogoPinHTML(opts) {
    injectStyle();
    const o = opts || {};
    const size = o.size || 48;
    const active = !!o.active;
    const num = (o.num != null) ? String(o.num) : null;
    const badgeSize = Math.max(14, Math.round(size * 0.32));
    const inner = Math.round(size * 0.86);
    const shadow = active
      ? '0 6px 20px rgba(0,0,0,.48),0 0 0 2px rgba(251,191,36,.55),0 0 24px rgba(251,191,36,.42)'
      : '0 4px 12px rgba(0,0,0,.38),0 1px 3px rgba(0,0,0,.2),inset 0 1px 0 rgba(255,255,255,.9)';
    // SVG fidèle: cercle #f3f4f6, texte FITNESS PARK italique noir, swoosh jaune.
    // viewBox 200x200 — proportions identiques à l'image de référence.
    return `<div class="fp-logo-pin${active ? ' fp-pin-active' : ''}" style="width:${size}px;height:${size}px;background:#f3f4f6;border-radius:50%;display:flex;align-items:center;justify-content:center;box-shadow:${shadow};cursor:pointer;position:relative;overflow:visible">
      <svg width="${inner}" height="${inner}" viewBox="0 0 200 200" xmlns="http://www.w3.org/2000/svg" style="display:block" aria-label="Fitness Park">
        <text x="100" y="95" font-family="'Helvetica Neue','Arial Black',Inter,sans-serif" font-weight="900" font-style="italic" font-size="30" fill="#1f2937" text-anchor="middle" dominant-baseline="middle" letter-spacing="-1" textLength="170" lengthAdjust="spacingAndGlyphs">FITNESS PARK</text>
        <path class="fp-logo-pin__swoosh" d="M 22 130 Q 62 110, 100 124 T 178 118" stroke="#fbbf24" stroke-width="9" fill="none" stroke-linecap="round"/>
      </svg>
      ${num != null ? `<div style="position:absolute;top:-4px;right:-4px;width:${badgeSize}px;height:${badgeSize}px;border-radius:50%;background:#1f2937;color:#fbbf24;font-size:${Math.round(badgeSize*0.58)}px;font-weight:900;display:flex;align-items:center;justify-content:center;border:1.5px solid #ffffff;box-shadow:0 2px 5px rgba(0,0,0,.45);font-family:Inter,Arial,sans-serif;line-height:1">${num}</div>` : ''}
    </div>`;
  };

  // v6.55 — signal au code inline (index.html) qu'il peut re-render les pins
  // avec le vrai logo. Avant ce signal, renderTargetPinsDesktop peut avoir
  // fallback au HTML simplifié "FP N" faute de fpLogoPinHTML dispo (script defer).
  try { window.dispatchEvent(new CustomEvent('fp:logos-ready')); } catch {}
})();
